pub async fn create_user_returning(pool: &sqlx::PgPool, name: &str, email: &str) -> Result<CreateUserReturningRow, sqlx::Error> {
    sqlx::query_as!(CreateUserReturningRow, "INSERT INTO users (name, email) VALUES ($1, $2) RETURNING id, name, created_at", name, email)
        .fetch_one(pool)
        .await
}

rust-sqlx.row_struct:
#[derive(Debug, sqlx::FromRow)]
pub struct CreateUserReturningRow {
    pub id: i32,
    pub name: String,
    pub created_at: chrono::DateTime<chrono::Utc>,
}

